import { Component, OnInit } from '@angular/core';
import { NavigationExtras, Router } from '@angular/router';
import { Subject } from 'rxjs';
import { AccountBlockingServiceService } from 'src/app/shared/services/account-blocking-service.service';
import { UsersService } from 'src/app/shared/services/user.service';

@Component({
  selector: 'npr-email-management',
  templateUrl: './email-management.component.html',
  styleUrls: ['./email-management.component.scss']
})
export class EmailManagementComponent implements OnInit {
  emaildata: any;
  user_id: string;
  role: string;
  dtOptions: DataTables.Settings = {};
  dtTrigger: Subject<any> = new Subject<any>();

  constructor(private accountBlockingService: AccountBlockingServiceService, private router: Router,private userApi:UsersService) { }

  ngOnInit(): void {
    this.user_id=sessionStorage.getItem('user_id');
    this.role=sessionStorage.getItem('user_role');
    this.getAllData();
   
    this.dtOptions = {
      pagingType: 'full_numbers',
      pageLength : 5,
      columnDefs: [ { type: 'date', 'targets': [2] } ],
      order: [[2, 'desc']],
      processing: true,
      lengthMenu: [[5, 10, 20, -1], [5, 10, 20, 30]],
      // columnDefs: [ { type: 'date', 'targets': [5] } ],
      // order: [[5, 'desc']],

    };
  }
  ngOnDestroy(): void {
    // Do not forget to unsubscribe the event
    this.dtTrigger.unsubscribe();
  }
  getEmail(email) {
    console.log("email",email);
    //console.log(row.modNO);
    const navigationExtras: NavigationExtras = {
      queryParams: {
        modifyNo:email.modNO,
        creator:email.inputBy,
        rstatus:email.recordStatus,
        vStatus:email.verifiedOnce,
        inputDate:email.inputTime,
        vDate:email.verifiedStatus,
        authtym:email.verifiedTime,
        authBy:email.verifiedBy,
        emailType:email.emailType
      }

    };
    console.log(email.emailType);
    this.accountBlockingService.sendNavParam(navigationExtras);
      this.router.navigate(['email-management/create']);
      // this.router.navigate(['email-management/create'],navigationExtras);
      console.log(navigationExtras);
  }
  getAllData() {
    this.accountBlockingService.getAllEmail().subscribe(emaildata => {
      this.emaildata = emaildata;
      this.dtTrigger.next();
      console.log(this.emaildata);
    })
    localStorage.setItem("EmailSwitch", "existing");
    localStorage.setItem("responseFromEmailSummary", this.emaildata);
  }
  createEmail(){
    this.router.navigate(['/email-management/create']);
    const navigationExtras: NavigationExtras = {
      queryParams: {}
      
    }
    console.log(navigationExtras);
    
    this.accountBlockingService.sendNavParam(navigationExtras);
  }

}
